import{_ as o,o as t,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"49. Overtime","description":"","frontmatter":{"title":"49. Overtime","eba":"Nurses and Midwives 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/nurses-midwives/hours-of-work/49-overtime.md","filePath":"ebas/nurses-midwives/hours-of-work/49-overtime.md"}'),a={name:"ebas/nurses-midwives/hours-of-work/49-overtime.md"};function s(n,e,l,p,h,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_49-overtime" tabindex="-1">49. Overtime <a class="header-anchor" href="#_49-overtime" aria-label="Permalink to &quot;49. Overtime&quot;">​</a></h1><p>This clause does not apply to a DON at an Employer where a Deputy or Assistant DON is also employed.</p><p>Note: See <a href="/eba/ebas/nurses-midwives/allowances/33-allowances-related-to-overtime.html">clause 33</a> for allowances which may be applicable to periods of overtime. See also <a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a> (public holidays)</p><p><strong>49.1</strong> An Employer may require an Employee to work &quot;reasonable overtime&quot; at overtime rates and such an Employee will work overtime in accordance with such a requirement.</p><p><strong>49.2</strong> Overtime Penalty Rates</p><p><strong>(a)</strong> Overtime means work requested or directed by the Employer that is performed:</p><p><strong>(i)</strong> in addition to the full-time ordinary hours described at <a href="/eba/ebas/nurses-midwives/hours-of-work/42-hours-of-work.html">clause 42.1</a> (Hours for an ordinary week&#39;s work), save for the exception at clause</p><p><strong>55.1</strong> relating to Daylight Saving Time;</p><p><strong>(ii)</strong> in addition to <a href="/eba/ebas/nurses-midwives/hours-of-work/42-hours-of-work.html">clause 42.3</a> and subject to <a href="/eba/ebas/nurses-midwives/hours-of-work/55-daylight-saving.html">clause 55.1</a>;</p><p><strong>(iii)</strong> in addition to the Employee&#39;s rostered shift length;</p><p><strong>(iv)</strong> where a break of at least eight hours has not been provided between successive shifts – for all work performed until a break of eight hours is provided; or</p><p><strong>(v)</strong> as recall to duty, including recall on a public holiday.</p><p><strong>(b)</strong> Overtime is also as provided at <a href="/eba/ebas/nurses-midwives/hours-of-work/53-rest-period-after-overtime-recall.html">clause 53</a> (Rest Period after Overtime/Recall).</p><p><strong>(c)</strong> Overtime (including for a double shift as defined at subclause 49.6(c)) is to be paid as follows:</p><p><strong>(i)</strong> Monday to Friday (inclusive) – time and half for the first two hours, double time thereafter;</p><p><strong>(ii)</strong> Saturday and Sunday – double time; and</p><p><strong>(iii)</strong> Public Holidays – see <a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a> (Public Holidays).</p><p><strong>(d)</strong> For a casual Employee, Overtime will be calculated and paid at the rate of:</p><p><strong>(i)</strong> Monday to Friday (inclusive) – 175% for the first two hours (which equates to time and a half plus the casual loading of 25%) and 225% (double time plus casual loading of 25%) for all subsequent hours;</p><p><strong>(ii)</strong> Saturday and Sunday– 225% (which equates to double time plus the casual loading of 25%); and</p><p><strong>(iii)</strong> Public Holidays – see <a href="/eba/ebas/medical-specialists/leave/56-public-holidays.html">clause 56</a> (Public Holidays).</p><p><strong>(e)</strong> When calculating overtime payments, each day or shift will stand alone. Where a period of overtime worked commences on one day and finishes on another, the calculation of overtime will be treated as if the overtime took place in a single day or shift.</p><p>Example: An Employee commences overtime at 10pm on Monday and it concludes at 2am. The Employee shall be paid time and a half for the first 2 hours (10pm to midnight) and double time thereafter (midnight to 2am).</p><p><strong>(f)</strong> If, due to organisational or institutional circumstances, difficulties arise from the requirement that overtime will only be paid if the Employee is requested or directed by the Employer to perform overtime work, the matter may be dealt with in accordance with the Dispute Resolution Procedure in the Agreement.</p><p><strong>(g)</strong> Rest break during overtime</p><p>An Employee working overtime will take a paid rest break of 20 minutes after each four hours of overtime worked if required to continue to work after the rest break.</p><p><strong>49.3</strong> Reasonable overtime</p><p><strong>(a)</strong> In determining whether overtime is &quot;reasonable overtime&quot; for the purposes of clause 49.1, the following must be taken into account:</p><p><strong>(i)</strong> any risk to Employee health and safety from working the additional hours;</p><p><strong>(ii)</strong> the Employee&#39;s personal circumstances, including family responsibilities;</p><p><strong>(iii)</strong> the needs of the workplace or enterprise in which the Employee is employed;</p><p><strong>(iv)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours;</p><p><strong>(v)</strong> any notice given by the Employer of any request or requirement to work the additional hours;</p><p><strong>(vi)</strong> any notice given by the Employee of their intention to refuse to work the additional hours;</p><p><strong>(vii)</strong> the usual patterns of work in the industry, or the part of an industry, in which the Employee works;</p><p><strong>(viii)</strong> the nature of the Employee&#39;s role, and the Employee&#39;s level of responsibility; and</p><p><strong>(ix)</strong> any other relevant matter.</p><p><strong>(b)</strong> An Employee may refuse to work overtime, if the request is unreasonable.</p><p><strong>49.4</strong> Approval of Overtime</p><p><strong>(a)</strong> A request or direction made by the nurse or midwife in charge of the ward that an Employee work overtime is, for the purposes of this clause, a direction or request of the Employer regardless of whether subclause 49.4(b) is complied with.</p><p><strong>(b)</strong> An Employer may create policies and procedures regarding the process the nurse or midwife in charge of the ward is required to undertake prior to approving overtime.</p><p><strong>49.5</strong> Time off instead of payment for overtime</p><p>An Employee may, with the consent of the Employer, elect to take time off in lieu of payment for overtime worked for a period equivalent to the overtime worked, plus a period equivalent to the overtime penalty incurred. Time off in lieu of overtime will be taken at a time mutually agreed between the Employer and the Employee, provided that the accrual of such time off will not extend beyond a 28 day period. Where the time off is not taken within 28 days, the overtime worked will be paid in the next pay period.</p><p><strong>49.6</strong> Transport following overtime</p><p><strong>(a)</strong> Where an Employee finishes a period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee, including the return journey where the Employee&#39;s vehicle remains at the workplace.</p><p><strong>(b)</strong> Where overtime is a result of a double shift, the provisions at subclause 49.6(c) below (Additional Provisions for Double Shifts) also apply.</p><p><strong>(c)</strong> Additional Provisions for Double Shifts</p><p><strong>(i)</strong> A double shift occurs where a non-casual Employee has worked 14 or more continuous hours (inclusive of any paid or unpaid breaks).</p><p><strong>(ii)</strong> An Employee who works a double shift will be entitled to overtime in accordance with subclause 49.2(c).</p><p><strong>(iii)</strong> If an Employee works a double shift (which should only occur in emergency circumstances) the following will apply to mitigate the risk of fatigue and clinical error:</p><p><strong>(A)</strong> allow breaks of at least 10 minutes&#39; duration in each two hours worked; and</p><p><strong>(B)</strong> adequate transport will be provided free of cost to the Employee, including the return journey where the Employee&#39;s vehicle remains at the workplace.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',53)])])}const c=o(a,[["render",s]]);export{u as __pageData,c as default};
